import React, { useContext } from "react";
import { Link, graphql } from "gatsby";
import Layout, { LangContext } from "../components/Layout";
import SEO from "../components/SEO";
import DataPanel from "../components/DataPanel";
import { pickLangNodes, langSlug } from "../utils/i18n";

const CategoryTemplate = ({ data, pageContext }) => {
  const { lang } = useContext(LangContext);
  const { categoryLabel, categoryIcon } = pageContext;
  const nodes = pickLangNodes(data.allMarkdownRemark.nodes, lang);

  const l = (vi, en) => lang === "vi" ? vi : en;

  return (
    <Layout>
      <nav className="report-breadcrumb" aria-label="Breadcrumb">
        <Link to={langSlug("/", lang)}>{l("Bảng điều khiển", "Dashboard")}</Link>
        <span className="breadcrumb-sep">›</span>
        <Link to={langSlug("/reports/", lang)}>{l("Báo cáo", "Reports")}</Link>
        <span className="breadcrumb-sep">›</span>
        <span className="breadcrumb-current">{categoryIcon} {categoryLabel}</span>
      </nav>

      <div className="page-header">
        <h1>{categoryIcon} {categoryLabel}</h1>
        <p className="page-subtitle">{nodes.length} {l("báo cáo", "reports")}</p>
      </div>

      <DataPanel title={`${l("Tất cả báo cáo", "All")} ${categoryLabel} ${l("", "Reports")}`}>
        <div className="report-list">
          {nodes.map((node) => (
            <Link key={node.id} to={langSlug(node.fields?.slug || "/", lang)} className="report-list-item">
              <span className="report-date">{node.fields?.date || "—"}</span>
              <span className="report-title">
                {node.frontmatter?.title || `${categoryLabel} — ${node.fields?.date || "Report"}`}
              </span>
            </Link>
          ))}
        </div>
      </DataPanel>
    </Layout>
  );
};

export default CategoryTemplate;

export const Head = ({ pageContext, location }) => {
  const { categoryLabel } = pageContext;
  const lang = location?.pathname?.startsWith("/en") ? "en" : "vi";
  return (
    <SEO
      title={`${categoryLabel} Reports — Bobbie Intelligence`}
      description={`Browse all ${categoryLabel} intelligence reports from Bobbie Intelligence.`}
      path={`/reports/${pageContext.category}/`}
      lang={lang}
    />
  );
};

export const query = graphql`
  query CategoryPage($category: String!) {
    allMarkdownRemark(
      filter: { fields: { category: { eq: $category } } }
      sort: { fields: { date: DESC } }
    ) {
      nodes {
        id
        fields {
          slug
          category
          categoryLabel
          categoryIcon
          date
          lang
          baseName
        }
        frontmatter {
          title
          date
        }
        excerpt
      }
    }
  }
`;
